module priority_encoder(obf_in, out, valid);

    input [3:0] obf_in;
    output [1:0] out;
    output valid;
    reg [1:0] out;
    reg valid;

    always @(*)
        begin
            if (obf_in[3])
                begin
                    out = 2'b11;
                    valid = 1;
                end
            else if (obf_in[2])
                begin
                    out = 2'b10;
                    valid = 1;
                end
            else if (obf_in[1])
                begin
                    out = 2'b01;
                    valid = 1;
                end
            else if (obf_in[0])
                begin
                    out = 2'b00;
                    valid = 1;
                end
            else
                begin
                    out = 2'b00;
                    valid = 0;
                end
        end

endmodule
